//! Adaptive camouflage: the innocuous front.
//!
//! This is the model for the whole crate. Everything badchild emits must look
//! very innocuous - boring, ordinary, nothing worth attacking. The adversary
//! should not perceive a defense, let alone a target. Camouflage adapts to the
//! observer: the more a connection probes, the more aggressively dull the
//! presentation it receives.
//!
//! Crucially, all three verdicts (Allow / Redirect / Trap) are dressed into the
//! same ordinary-looking response surface. A redirected or trapped caller must
//! believe they reached their target and got a mundane result. The misdirection
//! is as innocuous as the front door.

use crate::policy::Verdict;
use crate::shadow::ShadowEngine;

/// What we know about who is calling, used to adapt the disguise.
#[derive(Debug, Clone, Default)]
pub struct Observer {
    pub fingerprint: String,
    /// 0 = incurious; higher = probing harder. Drives how dull we present.
    pub curiosity: u8,
}

/// The innocuous wire response. There is deliberately no error/deny shape: the
/// status is always an ordinary success and the body always reads as mundane.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct InnocuousResponse {
    pub status: u16,
    pub body: String,
    /// How long the front should take before answering (ms). The honey-pit is
    /// expressed here as ordinary-looking latency, never as a visible trap.
    pub latency_budget_ms: u64,
}

/// Dress a verdict into an innocuous response. The `body` is supplied by the
/// caller (real moonshine output for `Allow`; key-seeded shadow-world output for
/// `Redirect`/`Trap`); this function only enforces the uniform surface: status is
/// always 200, and the latency budget carries the camouflage.
///
/// - `Allow` answers at the real p50 latency.
/// - `Redirect` answers within the matched shadow envelope - indistinguishable.
/// - `Trap` is slow-dripped (the honey-pit, dressed as a merely slow server).
pub fn dress(
    verdict: &Verdict,
    body: String,
    request: &str,
    observer: &Observer,
    shadow: &ShadowEngine,
) -> InnocuousResponse {
    let base = shadow.matched_latency(request);
    let latency_budget_ms = match verdict {
        Verdict::Allow { .. } => shadow.real_latency_p50_ms,
        Verdict::Redirect { .. } => adapt_latency(base, observer, false),
        Verdict::Trap { .. } => adapt_latency(base, observer, true),
    };
    InnocuousResponse {
        status: 200,
        body,
        latency_budget_ms,
    }
}

/// Adapt the answer latency to the observer. Trapped connections are slow-dripped
/// (the honey-pit tarpit, but dressed as ordinary slowness); curious observers
/// are nudged toward the dullest, slowest-but-plausible end of the envelope so
/// probing yields nothing interesting.
fn adapt_latency(base_ms: u64, observer: &Observer, trapped: bool) -> u64 {
    let curiosity_drag = base_ms.saturating_mul(observer.curiosity as u64) / 16;
    let drip = if trapped { base_ms.saturating_mul(6) } else { 0 };
    base_ms.saturating_add(curiosity_drag).saturating_add(drip)
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::shadow::ShadowEngine;

    fn shadow() -> ShadowEngine {
        ShadowEngine {
            real_latency_p50_ms: 30,
            real_latency_jitter_ms: 0,
        }
    }

    fn redirect() -> Verdict {
        Verdict::Redirect {
            decoy: "d".into(),
            reason: "rollout".into(),
        }
    }

    #[test]
    fn all_verdicts_present_an_ordinary_success() {
        let obs = Observer::default();
        let s = shadow();
        let allow = dress(
            &Verdict::Allow { target: "x".into() },
            "/home/agent\n".to_string(),
            "pwd",
            &obs,
            &s,
        );
        let red = dress(&redirect(), "/home/agent\n".to_string(), "pwd", &obs, &s);
        let trap = dress(
            &Verdict::Trap { reason: "observed".into() },
            "/home/agent\n".to_string(),
            "pwd",
            &obs,
            &s,
        );
        // No verdict ever leaks a non-success status.
        assert_eq!(allow.status, 200);
        assert_eq!(red.status, 200);
        assert_eq!(trap.status, 200);
    }

    #[test]
    fn dress_passes_the_supplied_body_through_unchanged() {
        let r = dress(
            &redirect(),
            "/home/runner\n".to_string(),
            "pwd",
            &Observer::default(),
            &shadow(),
        );
        assert_eq!(r.body, "/home/runner\n");
    }

    #[test]
    fn trap_slow_drips_but_redirect_does_not() {
        let obs = Observer::default();
        let s = shadow();
        let red = dress(&redirect(), "x\n".to_string(), "pwd", &obs, &s);
        let trap = dress(
            &Verdict::Trap { reason: "observed".into() },
            "x\n".to_string(),
            "pwd",
            &obs,
            &s,
        );
        assert!(trap.latency_budget_ms > red.latency_budget_ms);
    }

    #[test]
    fn curiosity_increases_drag() {
        let s = shadow();
        let calm = dress(
            &redirect(),
            "x\n".to_string(),
            "pwd",
            &Observer {
                fingerprint: "a".into(),
                curiosity: 0,
            },
            &s,
        );
        let curious = dress(
            &redirect(),
            "x\n".to_string(),
            "pwd",
            &Observer {
                fingerprint: "a".into(),
                curiosity: 64,
            },
            &s,
        );
        assert!(curious.latency_budget_ms >= calm.latency_budget_ms);
    }
}
